import React, { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import styled from 'styled-components';
import { motion } from 'framer-motion';
import { useAuth } from '../contexts/AuthContext';
import PERatioGraph from '../components/PERatioGraph';
import KMeansClusteringGraph from '../components/KMeansClusteringGraph';

const PortfolioSectorContainer = styled.div`
  max-width: 1400px;
  margin: 0 auto;
  padding: 2rem;
  min-height: 80vh;
`;

const PageHeader = styled(motion.div)`
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 2rem;
  flex-wrap: wrap;
  gap: 1rem;
`;

const SectorTitle = styled(motion.h1)`
  font-size: 2.8rem;
  background: linear-gradient(45deg, #4ecdc4, #ff6b6b);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  margin: 0;
  text-transform: capitalize;
`;

const BackButton = styled(motion.button)`
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  border: none;
  color: white;
  padding: 0.8rem 1.5rem;
  border-radius: 10px;
  cursor: pointer;
  font-weight: 600;
  transition: all 0.3s ease;
  
  &:hover {
    transform: translateY(-2px);
    box-shadow: 0 5px 15px rgba(0, 0, 0, 0.3);
  }
`;

const SectorStatsContainer = styled(motion.div)`
  background: rgba(255, 255, 255, 0.08);
  backdrop-filter: blur(12px);
  border-radius: 15px;
  padding: 1.5rem;
  margin-bottom: 2rem;
  border: 1px solid rgba(255, 255, 255, 0.1);
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
  gap: 2rem;
`;

const StatBox = styled.div`
  text-align: center;
  padding: 1rem;
  border-radius: 10px;
  background: rgba(255, 255, 255, 0.05);
`;

const StatLabel = styled.div`
  font-size: 0.9rem;
  color: #cccccc;
  margin-bottom: 0.5rem;
  text-transform: uppercase;
  letter-spacing: 0.5px;
`;

const StatValue = styled.div`
  font-size: 2rem;
  font-weight: bold;
  color: #4ecdc4;
`;

const StocksGrid = styled(motion.div)`
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(320px, 1fr));
  gap: 2rem;
  margin-top: 2rem;
`;

const StockCard = styled(motion.div)`
  background: rgba(255, 255, 255, 0.1);
  backdrop-filter: blur(10px);
  border-radius: 15px;
  padding: 1.5rem;
  border: 1px solid rgba(255, 255, 255, 0.1);
  transition: all 0.3s ease;
  cursor: pointer;

  &:hover {
    transform: translateY(-5px);
    box-shadow: 0 10px 30px rgba(0, 0, 0, 0.3);
    border-color: rgba(78, 205, 196, 0.5);
  }
`;

const StockHeader = styled.div`
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  margin-bottom: 1rem;
`;

const StockInfo = styled.div`
  display: flex;
  flex-direction: column;
`;

const StockName = styled.h3`
  font-size: 1.2rem;
  color: #ffffff;
  margin: 0;
`;

const StockSymbol = styled.p`
  font-size: 0.9rem;
  color: #4ecdc4;
  margin: 0.2rem 0;
  font-weight: 600;
`;

const RemoveButton = styled.button`
  background: rgba(255, 107, 107, 0.2);
  border: 1px solid rgba(255, 107, 107, 0.5);
  color: #ff6b6b;
  padding: 0.4rem 0.8rem;
  border-radius: 5px;
  cursor: pointer;
  font-weight: 600;
  transition: all 0.3s ease;

  &:hover {
    background: rgba(255, 107, 107, 0.4);
    transform: scale(1.05);
  }
`;

const StockPrice = styled.div`
  font-size: 1.8rem;
  font-weight: bold;
  color: #00b894;
  margin-bottom: 0.5rem;
`;

const StockChange = styled.div<{ positive: boolean }>`
  color: ${props => props.positive ? '#00b894' : '#ff6b6b'};
  font-size: 1rem;
  margin-bottom: 1rem;
  font-weight: 600;
`;

const StockStats = styled.div`
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 1rem;
  margin: 1.5rem 0;
  padding: 1rem 0;
  border-top: 1px solid rgba(255, 255, 255, 0.1);
  border-bottom: 1px solid rgba(255, 255, 255, 0.1);
`;

const StatItem = styled.div`
  text-align: left;
`;

const StatItemLabel = styled.div`
  font-size: 0.75rem;
  color: #cccccc;
  text-transform: uppercase;
  letter-spacing: 0.3px;
  margin-bottom: 0.3rem;
`;

const StatItemValue = styled.div`
  font-size: 1.1rem;
  color: #ffffff;
  font-weight: 600;
`;

const DetailButton = styled.button`
  width: 100%;
  background: linear-gradient(135deg, #4ecdc4 0%, #44a08d 100%);
  border: none;
  color: white;
  padding: 0.7rem;
  border-radius: 8px;
  cursor: pointer;
  font-weight: 600;
  transition: all 0.3s ease;

  &:hover {
    transform: translateY(-2px);
    box-shadow: 0 5px 15px rgba(0, 0, 0, 0.2);
  }
`;

const ExpandedCard = styled(motion.div)`
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(0, 0, 0, 0.9);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1000;
  padding: 2rem;
`;

const ExpandedCardContent = styled(motion.div)`
  background: rgba(255, 255, 255, 0.1);
  backdrop-filter: blur(10px);
  border-radius: 15px;
  padding: 2rem;
  border: 1px solid rgba(255, 255, 255, 0.1);
  max-width: 900px;
  max-height: 90vh;
  overflow-y: auto;
  width: 100%;
  position: relative;
`;

const CloseButton = styled.button`
  position: absolute;
  top: 1rem;
  right: 1rem;
  background: rgba(255, 107, 107, 0.2);
  border: 1px solid rgba(255, 107, 107, 0.5);
  color: #ff6b6b;
  padding: 0.5rem 0.8rem;
  border-radius: 5px;
  cursor: pointer;
  font-weight: 600;
  transition: all 0.3s ease;

  &:hover {
    background: rgba(255, 107, 107, 0.4);
  }
`;

const EmptyState = styled(motion.div)`
  text-align: center;
  padding: 4rem 2rem;
  color: #cccccc;
`;

const SECTOR_ICONS: { [key: string]: string } = {
  'it': '💻',
  'banking': '🏦',
  'automobile': '🚗',
  'energy': '⚡',
  'pharma': '💊',
  'fmcg': '🛒',
  'metals': '⛏️',
  'finance': '💰',
  'hospitality': '🏨',
  'realty': '🏢'
};

const PortfolioSector: React.FC = () => {
  const { sector } = useParams<{ sector: string }>();
  const navigate = useNavigate();
  const { portfolioBySector, removeFromPortfolio } = useAuth();
  const [expandedSymbol, setExpandedSymbol] = useState<string | null>(null);

  if (!sector) {
    return <div>Invalid sector</div>;
  }

  const sectorName = sector.toLowerCase();
  const sectorStocks = portfolioBySector[sectorName] || [];
  const icon = SECTOR_ICONS[sectorName] || '📊';

  const totalValue = sectorStocks.reduce((total, item) => total + item.price, 0);
  const totalChange = sectorStocks.reduce((total, item) => total + item.change, 0);
  const avgChangePercent = sectorStocks.length > 0 ? totalChange / sectorStocks.length : 0;

  const expandedStock = sectorStocks.find(s => s.symbol === expandedSymbol);

  return (
    <PortfolioSectorContainer>
      <PageHeader
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
      >
        <div>
          <SectorTitle>
            {icon} {sectorName.toUpperCase()} PORTFOLIO
          </SectorTitle>
        </div>
        <BackButton
          onClick={() => navigate('/portfolio')}
          whileHover={{ scale: 1.05 }}
          whileTap={{ scale: 0.95 }}
        >
          ← Back to Portfolio
        </BackButton>
      </PageHeader>

      {sectorStocks.length === 0 ? (
        <EmptyState
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 0.3 }}
        >
          <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>📭</div>
          <h2>No stocks in {sectorName} sector</h2>
          <p>Add stocks from the {sectorName} sector to view them here</p>
          <BackButton
            onClick={() => navigate('/stocks')}
            style={{ marginTop: '1rem', display: 'inline-block' }}
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
          >
            Browse {sectorName.charAt(0).toUpperCase() + sectorName.slice(1)} Stocks
          </BackButton>
        </EmptyState>
      ) : (
        <>
          {/* Sector Statistics */}
          <SectorStatsContainer
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.2 }}
          >
            <StatBox>
              <StatLabel>Total Value</StatLabel>
              <StatValue>${totalValue.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</StatValue>
            </StatBox>
            <StatBox>
              <StatLabel>Stocks</StatLabel>
              <StatValue>{sectorStocks.length}</StatValue>
            </StatBox>
            <StatBox>
              <StatLabel>Avg Change</StatLabel>
              <StatValue style={{ color: avgChangePercent >= 0 ? '#00b894' : '#ff6b6b' }}>
                {avgChangePercent >= 0 ? '+' : ''}{avgChangePercent.toFixed(2)}%
              </StatValue>
            </StatBox>
            <StatBox>
              <StatLabel>Total Change</StatLabel>
              <StatValue style={{ color: totalChange >= 0 ? '#00b894' : '#ff6b6b' }}>
                {totalChange >= 0 ? '+' : ''}${totalChange.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
              </StatValue>
            </StatBox>
          </SectorStatsContainer>

          {/* Stocks Grid */}
          <StocksGrid
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.3 }}
          >
            {sectorStocks.map((stock, index) => (
              <StockCard
                key={stock.symbol}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 0.3 + index * 0.05 }}
                whileHover={{ scale: 1.02 }}
              >
                <StockHeader>
                  <StockInfo>
                    <StockName>{stock.name}</StockName>
                    <StockSymbol>{stock.symbol}</StockSymbol>
                  </StockInfo>
                  <RemoveButton
                    onClick={() => removeFromPortfolio(stock.symbol)}
                  >
                    ✕
                  </RemoveButton>
                </StockHeader>

                <StockPrice>
                  ${stock.price.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                </StockPrice>
                <StockChange positive={stock.change >= 0}>
                  {stock.change >= 0 ? '+' : ''}{stock.change.toFixed(2)}%{' '}
                  {stock.change >= 0 ? '📈' : '📉'}
                </StockChange>

                <StockStats>
                  <StatItem>
                    <StatItemLabel>Added</StatItemLabel>
                    <StatItemValue>
                      {new Date(stock.addedAt).toLocaleDateString()}
                    </StatItemValue>
                  </StatItem>
                  <StatItem>
                    <StatItemLabel>Sector</StatItemLabel>
                    <StatItemValue style={{ textTransform: 'capitalize' }}>
                      {stock.sector || 'Unknown'}
                    </StatItemValue>
                  </StatItem>
                </StockStats>

                <DetailButton onClick={() => setExpandedSymbol(stock.symbol)}>
                  View Details & Charts 📊
                </DetailButton>
              </StockCard>
            ))}
          </StocksGrid>

          {/* Expanded Detail View */}
          {expandedStock && (
            <ExpandedCard
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ duration: 0.3 }}
              onClick={() => setExpandedSymbol(null)}
            >
              <ExpandedCardContent
                initial={{ scale: 0.9, opacity: 0 }}
                animate={{ scale: 1, opacity: 1 }}
                transition={{ duration: 0.3 }}
                onClick={(e) => e.stopPropagation()}
              >
                <CloseButton onClick={() => setExpandedSymbol(null)}>✕ Close</CloseButton>

                <div style={{ marginTop: '2rem' }}>
                  <StockName>{expandedStock.name}</StockName>
                  <StockSymbol>{expandedStock.symbol}</StockSymbol>
                </div>

                <StockPrice style={{ marginTop: '1rem' }}>
                  ${expandedStock.price.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                </StockPrice>
                <StockChange positive={expandedStock.change >= 0}>
                  {expandedStock.change >= 0 ? '+' : ''}{expandedStock.change.toFixed(2)}% {expandedStock.change >= 0 ? '📈' : '📉'}
                </StockChange>

                {/* Charts Section */}
                <div style={{ marginTop: '2rem', borderTop: '1px solid rgba(255,255,255,0.1)', paddingTop: '2rem' }}>
                  <div style={{ marginBottom: '3rem' }}>
                    <h3 style={{ color: '#4ecdc4', marginBottom: '1rem' }}>P/E Ratio Analysis</h3>
                    <PERatioGraph stockSymbol={expandedStock.symbol} stockPrice={expandedStock.price} />
                  </div>

                  <div style={{ marginBottom: '2rem' }}>
                    <h3 style={{ color: '#4ecdc4', marginBottom: '1rem' }}>K-Means Clustering</h3>
                    <KMeansClusteringGraph
                      stockSymbol={expandedStock.symbol}
                      stockPrice={expandedStock.price}
                      stockName={expandedStock.name}
                    />
                  </div>
                </div>

                {/* Stock Details */}
                <div style={{ marginTop: '2rem', paddingTop: '2rem', borderTop: '1px solid rgba(255,255,255,0.1)' }}>
                  <h3 style={{ color: '#4ecdc4', marginBottom: '1rem' }}>Details</h3>
                  <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.5rem', color: '#cccccc' }}>
                    <div>
                      <div style={{ fontSize: '0.85rem', color: '#999', marginBottom: '0.3rem' }}>ADDED ON</div>
                      <div style={{ fontSize: '1.1rem', color: '#fff' }}>
                        {new Date(expandedStock.addedAt).toLocaleDateString()}
                      </div>
                    </div>
                    <div>
                      <div style={{ fontSize: '0.85rem', color: '#999', marginBottom: '0.3rem' }}>SECTOR</div>
                      <div style={{ fontSize: '1.1rem', color: '#fff', textTransform: 'capitalize' }}>
                        {expandedStock.sector || 'Unknown'}
                      </div>
                    </div>
                  </div>
                </div>

                <div style={{ marginTop: '2rem' }}>
                  <RemoveButton
                    onClick={() => {
                      removeFromPortfolio(expandedStock.symbol);
                      setExpandedSymbol(null);
                    }}
                    style={{ width: '100%', padding: '0.8rem' }}
                  >
                    Remove from Portfolio
                  </RemoveButton>
                </div>
              </ExpandedCardContent>
            </ExpandedCard>
          )}
        </>
      )}
    </PortfolioSectorContainer>
  );
};

export default PortfolioSector;
